// Spieler in den Draft-Pool laden
function loadUFLPool() {
  if (!state.pool.length) {
    state.pool = UFL_PLAYER_POOL.map(p => ({
      name: p.name,
      pos:  p.pos,
      rating: p.rating,
      img:  p.img || ''
    }));
    renderAdminPool();
    checkReady();
  }
}
